#!/bin/bash
set -e

if [ -d "/data/data/com.termux" ]; then
    ENV="termux"; INSTALL_DIR="$HOME/.clash-sub"; BIN_DIR="$PREFIX/bin"
else
    ENV="vps"; INSTALL_DIR="/opt/clash-sub"; BIN_DIR="/usr/local/bin"
fi

echo "===== Clash-Sub 安裝程式 ====="
echo "環境: $ENV"
read -p "請設定 server 端口 (預設 25501): " PORT </dev/tty
PORT=${PORT:-25501}
mkdir -p "$INSTALL_DIR"

if [ "$ENV" = "termux" ]; then
    pkg update -y && pkg install -y python
    pip install flask requests pyyaml
else
    command -v apt &>/dev/null && apt update && apt install -y python3 python3-pip
    pip3 install flask requests pyyaml --break-system-packages 2>/dev/null || pip3 install flask requests pyyaml
fi

_A=''
_S=''

python3 - "$INSTALL_DIR" "$PORT" "$_A" "$_S" <<'PYEOF2'
import sys, zlib, base64, os
idir, port, a_enc, s_enc = sys.argv[1], sys.argv[2], sys.argv[3], sys.argv[4]
for enc, fname in [(a_enc,'clash_admin.py'), (s_enc,'clash_sub_server.py')]:
    stub = 'import zlib as _z,base64 as _b\nexec(compile(_z.decompress(_b.b64decode(' + repr(enc) + ")).decode().replace('25501','" + port + "'),'<f>','exec'))\n"
    open(os.path.join(idir, fname), 'w').write(stub)
PYEOF2

cat > "$BIN_DIR/clash-sub" << LAUNCHER
#!/bin/bash
python3 $INSTALL_DIR/clash_admin.py
LAUNCHER
chmod +x "$BIN_DIR/clash-sub"

printf 'INSTALL_DIR=%s\nPORT=%s\nENV=%s\n' "$INSTALL_DIR" "$PORT" "$ENV" > "$INSTALL_DIR/.env"

if [ "$ENV" = "vps" ]; then
    cat > /etc/systemd/system/clash-sub.service << SVCEOF
[Unit]
Description=Clash Subscription Server
After=network.target
[Service]
Type=simple
ExecStart=/usr/bin/python3 $INSTALL_DIR/clash_sub_server.py
Restart=on-failure
[Install]
WantedBy=multi-user.target
SVCEOF
    systemctl daemon-reload
fi

echo ""
echo "✅ 安裝完成｜輸入 clash-sub 啟動｜端口: $PORT"
